package ccxtpro
import ccxt "github.com/ccxt/ccxt/go/v4"
type Lighter struct {
   *LighterCore
   Core *LighterCore
   exchangeTyped *ccxt.Lighter
}

func NewLighter(userConfig map[string]interface{}) *Lighter {
   p := NewLighterCore()
   p.Init(userConfig)
   return &Lighter{
       LighterCore: p,
       Core:  p,
       exchangeTyped: ccxt.NewLighterFromCore(p.base),
   }
}


